using System;

class Program
{
    static void Main()
    {
        Span<nint> nints = stackalloc nint[4];
        nints[0] = 42;
        nints[1] = nint.MaxValue;
        nints[2] = nint.MinValue;
        nints[3] = (nint)123456789;

        for (int i = 0; i < nints.Length; i++)
            Console.WriteLine($"nints[{i}] = {nints[i]}");

        Span<nuint> nuints = stackalloc nuint[2];
        nuints[0] = nuint.MaxValue;
        nuints[1] = 0;

        for (int i = 0; i < nuints.Length; i++)
            Console.WriteLine($"nuints[{i}] = {nuints[i]}");

        Console.WriteLine($"\nSize of nint: {sizeof(nint)} bytes");
        Console.WriteLine($"Size of nuint: {sizeof(nuint)} bytes");
    }
}
EOF
